     3→import React, { useState, useEffect } from 'react';
     4→import {
     5→  Card,
     6→  Elevation,
     7→  Button,
     8→  Callout,
     9→  Intent,
    10→  Tag,
    11→  InputGroup,
    12→  Checkbox,
    13→  HTMLSelect,
    14→  Dialog,
    15→  Classes,
    16→  Spinner,
    17→} from '@blueprintjs/core';
    18→import { apiFetch, servicesApi, trainsApi, type Service, type Train } from '@/lib/api';
    19→
    20→interface Scenario {
    21→  id: string;
    22→  name: string;
    23→  baseDate: string;
    24→  changeCount: number;
    25→  createdAt: string;
    26→}
    27→
    28→interface ComparisonMetric {
    29→  metric: string;
    30→  current: number;
    31→  projected: number;
    32→  change: number;
    33→  improved: boolean;
    34→}
    35→
    36→interface SimulationResult {
    37→  scenarioId: string;
    38→  projectedVariance: number;
    39→  projectedDeadRunning: number;
    40→  comparison: ComparisonMetric[];
    41→}
    42→
    43→interface AllocationChange {
    44→  serviceId: string;
    45→  serviceCode: string;
    46→  origin: string;
    47→  destination: string;
    48→  originalTrainId: string | null;
    49→  newTrainId: string;
    50→}
    51→
    52→/**
    53→ * Simulation Panel Component
    54→ *
    55→ * Enables what-if scenario creation and comparison.
    56→ */
    57→export function SimulationPanel() {
    58→  const [scenarios, setScenarios] = useState<Scenario[]>([]);
    59→  const [selectedScenario, setSelectedScenario] = useState<Scenario | null>(null);
    60→  const [simulationResult, setSimulationResult] = useState<SimulationResult | null>(null);
    61→  const [creating, setCreating] = useState(false);
    62→  const [running, setRunning] = useState(false);
    63→  const [newScenarioName, setNewScenarioName] = useState('');
    64→  const [error, setError] = useState<string | null>(null);
    65→
    66→  // Allocation Editor state
    67→  const [pendingServices, setPendingServices] = useState<Service[]>([]);
    68→  const [availableTrains, setAvailableTrains] = useState<Train[]>([]);
    69→  const [allocationChanges, setAllocationChanges] = useState<AllocationChange[]>([]);
    70→  const [loadingServices, setLoadingServices] = useState(false);
    71→
    72→  // Multi-scenario comparison state
    73→  const [selectedForComparison, setSelectedForComparison] = useState<Set<string>>(new Set());
    74→  const [comparisonResults, setComparisonResults] = useState<Map<string, SimulationResult>>(new Map());
    75→  const [comparing, setComparing] = useState(false);
    76→
    77→  // Apply to Live state
    78→  const [showApplyConfirm, setShowApplyConfirm] = useState(false);
    79→  const [applying, setApplying] = useState(false);
    80→
    81→  // Fetch services and trains when a scenario is selected
    82→  useEffect(() => {
    83→    if (selectedScenario) {
    84→      loadServicesAndTrains();
    85→    }
    86→  }, [selectedScenario]);
    87→
    88→  const loadServicesAndTrains = async () => {
    89→    setLoadingServices(true);
    90→    setError(null);
    91→
    92→    const [servicesResult, trainsResult] = await Promise.all([
    93→      servicesApi.getPending(),
    94→      trainsApi.getAll({ status: 'fit' }),
    95→    ]);
    96→
    97→    if (servicesResult.error) {
    98→      setError(servicesResult.error);
    99→    } else if (servicesResult.data) {
   100→      setPendingServices(servicesResult.data.services);
   101→    }
   102→
   103→    if (trainsResult.error) {
   104→      setError(trainsResult.error);
   105→    } else if (trainsResult.data) {
   106→      setAvailableTrains(trainsResult.data.trains);
   107→    }
   108→
   109→    setLoadingServices(false);
   110→  };
   111→
   112→  const handleTrainChange = (service: Service, newTrainId: string) => {
   113→    setAllocationChanges((prev) => {
   114→      const filtered = prev.filter((c) => c.serviceId !== service.id);
   115→
   116→      if (!newTrainId) {
   117→        return filtered;
   118→      }
   119→
   120→      return [
   121→        ...filtered,
   122→        {
   123→          serviceId: service.id,
   124→          serviceCode: service.serviceCode,
   125→          origin: service.origin,
   126→          destination: service.destination,
   127→          originalTrainId: null,
   128→          newTrainId,
   129→        },
   130→      ];
   131→    });
   132→
   133→    if (selectedScenario) {
   134→      setScenarios((prev) =>
   135→        prev.map((s) =>
   136→          s.id === selectedScenario.id
   137→            ? { ...s, changeCount: allocationChanges.length + 1 }
   138→            : s
   139→        )
   140→      );
   141→    }
   142→  };
   143→
   144→  const getSelectedTrainForService = (serviceId: string): string => {
   145→    const change = allocationChanges.find((c) => c.serviceId === serviceId);
   146→    return change?.newTrainId || '';
   147→  };
   148→
   149→  const removeAllocationChange = (serviceId: string) => {
   150→    setAllocationChanges((prev) => prev.filter((c) => c.serviceId !== serviceId));
   151→  };
   152→
   153→  const toggleComparisonSelection = (scenarioId: string) => {
   154→    setSelectedForComparison((prev) => {
   155→      const next = new Set(prev);
   156→      if (next.has(scenarioId)) {
   157→        next.delete(scenarioId);
   158→      } else if (next.size < 3) {
   159→        next.add(scenarioId);
   160→      }
   161→      return next;
   162→    });
   163→  };
   164→
   165→  const handleCompareScenarios = async () => {
   166→    if (selectedForComparison.size < 2) {
   167→      setError('Select at least 2 scenarios to compare');
   168→      return;
   169→    }
   170→
   171→    setComparing(true);
   172→    setError(null);
   173→    const results = new Map<string, SimulationResult>();
   174→
   175→    for (const scenarioId of Array.from(selectedForComparison)) {
   176→      const scenario = scenarios.find((s) => s.id === scenarioId);
   177→      if (!scenario || scenario.changeCount === 0) continue;
   178→
   179→      const { data } = await apiFetch<SimulationResult>(
   180→        `/api/simulation/${scenarioId}/run`,
   181→        {
   182→          method: 'POST',
   183→          body: JSON.stringify({ changes: [] }),
   184→        }
   185→      );
   186→
   187→      if (data) {
   188→        results.set(scenarioId, data);
   189→      }
   190→    }
   191→
   192→    setComparisonResults(results);
   193→    setComparing(false);
   194→  };
   195→
   196→  const handleApplyToLive = async () => {
   197→    if (!selectedScenario || allocationChanges.length === 0) return;
   198→
   199→    setApplying(true);
   200→    setError(null);
   201→
   202→    const { data, error: applyError } = await apiFetch<{ applied: number }>(
   203→      `/api/simulation/${selectedScenario.id}/apply`,
   204→      {
   205→        method: 'POST',
   206→        body: JSON.stringify({
   207→          changes: allocationChanges.map((change) => ({
   208→            serviceId: change.serviceId,
   209→            trainId: change.newTrainId,
   210→          })),
   211→        }),
   212→      }
   213→    );
   214→
   215→    if (applyError) {
   216→      setError(applyError);
   217→    } else if (data) {
   218→      setAllocationChanges([]);
   219→      setSimulationResult(null);
   220→      setShowApplyConfirm(false);
   221→      setScenarios((prev) => prev.filter((s) => s.id !== selectedScenario.id));
   222→      setSelectedScenario(null);
   223→    }
   224→
   225→    setApplying(false);
   226→  };
   227→
   228→  const handleCreateScenario = async () => {
   229→    if (!newScenarioName.trim()) return;
   230→
   231→    setCreating(true);
   232→    setError(null);
   233→
   234→    const { data, error } = await apiFetch<{ scenarioId: string } & Scenario>(
   235→      '/api/simulation/create',
   236→      {
   237→        method: 'POST',
   238→        body: JSON.stringify({
   239→          name: newScenarioName,
   240→          baseDate: new Date().toISOString().split('T')[0],
   241→        }),
   242→      }
   243→    );
   244→
   245→    if (error) {
   246→      setError(error);
   247→    } else if (data) {
   248→      const newScenario: Scenario = {
   249→        id: data.scenarioId,
   250→        name: newScenarioName,
   251→        baseDate: new Date().toISOString().split('T')[0],
   252→        changeCount: 0,
   253→        createdAt: new Date().toISOString(),
   254→      };
   255→      setScenarios((prev) => [...prev, newScenario]);
   256→      setSelectedScenario(newScenario);
   257→      setNewScenarioName('');
   258→    }
   259→
   260→    setCreating(false);
   261→  };
   262→
   263→  const handleRunSimulation = async () => {
   264→    if (!selectedScenario) return;
   265→
   266→    if (allocationChanges.length === 0) {
   267→      setError('Please assign at least one train to a service before running simulation');
   268→      return;
   269→    }
   270→
   271→    setRunning(true);
   272→    setError(null);
   273→
   274→    const { data, error: simError } = await apiFetch<SimulationResult>(
   275→      `/api/simulation/${selectedScenario.id}/run`,
   276→      {
   277→        method: 'POST',
   278→        body: JSON.stringify({
   279→          changes: allocationChanges.map((change) => ({
   280→            serviceId: change.serviceId,
   281→            originalTrainId: change.originalTrainId,
   282→            newTrainId: change.newTrainId,
   283→          })),
   284→        }),
   285→      }
   286→    );
   287→
   288→    if (simError) {
   289→      setError(simError);
   290→    } else if (data) {
   291→      setSimulationResult(data);
   292→    }
   293→
   294→    setRunning(false);
   295→  };
   296→
   297→  return (
   298→    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
   299→      {/* Create New Scenario */}
   300→      <Card elevation={Elevation.ONE} style={{ padding: 24 }}>
   301→        <h2 style={{ margin: '0 0 8px', fontSize: 18, fontWeight: 600, color: '#182026' }}>
   302→          What-If Simulation
   303→        </h2>
   304→        <p style={{ margin: '0 0 16px', fontSize: 14, color: '#5c7080' }}>
   305→          Create scenarios to test different allocation strategies and see projected impact on km variance.
   306→        </p>
   307→
   308→        <div style={{ display: 'flex', gap: 16 }}>
   309→          <InputGroup
   310→            value={newScenarioName}
