   513→                  <tr key={metric.metric} style={{ borderBottom: '1px solid #e1e8ed' }}>
   514→                    <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>{metric.metric}</td>
   515→                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', color: '#5c7080' }}>{metric.current}</td>
   516→                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', fontWeight: 500, color: '#182026' }}>{metric.projected}</td>
   517→                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', fontWeight: 500, color: metric.improved ? '#22c55e' : '#dc2626' }}>
   518→                      {metric.change > 0 ? '+' : ''}{metric.change}
   519→                      {metric.improved && ' ✓'}
   520→                    </td>
   521→                  </tr>
   522→                ))}
   523→              </tbody>
   524→            </table>
   525→          </div>
   526→
   527→          <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
   528→            <div>
   529→              <span style={{ fontSize: 14, color: '#5c7080', marginRight: 16 }}>
   530→                Projected Variance: <strong>{simulationResult.projectedVariance}%</strong>
   531→              </span>
   532→              <span style={{ fontSize: 14, color: '#5c7080' }}>
   533→                Dead Running: <strong>{simulationResult.projectedDeadRunning} km</strong>
   534→              </span>
   535→            </div>
   536→            <Button
   537→              onClick={() => setShowApplyConfirm(true)}
   538→              disabled={allocationChanges.length === 0}
   539→              intent={Intent.PRIMARY}
   540→            >
   541→              Apply to Live
   542→            </Button>
   543→          </div>
   544→        </Card>
   545→      )}
   546→
   547→      {/* Apply to Live Confirmation Dialog */}
   548→      <Dialog
   549→        isOpen={showApplyConfirm}
   550→        onClose={() => setShowApplyConfirm(false)}
   551→        title="Confirm Apply to Live"
   552→      >
   553→        <div className={Classes.DIALOG_BODY}>
   554→          <p>
   555→            This will create {allocationChanges.length} new allocation(s) in the live system.
   556→            This action cannot be undone.
   557→          </p>
   558→          <Callout intent={Intent.WARNING} style={{ marginTop: 16 }}>
   559→            <strong>Changes to apply:</strong>
   560→            <ul style={{ marginTop: 8, paddingLeft: 20 }}>
   561→              {allocationChanges.slice(0, 5).map((change) => (
   562→                <li key={change.serviceId}>
   563→                  {change.serviceCode}: Assign train {change.newTrainId.slice(0, 8)}...
   564→                </li>
   565→              ))}
   566→              {allocationChanges.length > 5 && (
   567→                <li>... and {allocationChanges.length - 5} more</li>
   568→              )}
   569→            </ul>
   570→          </Callout>
   571→        </div>
   572→        <div className={Classes.DIALOG_FOOTER}>
   573→          <div className={Classes.DIALOG_FOOTER_ACTIONS}>
   574→            <Button onClick={() => setShowApplyConfirm(false)}>Cancel</Button>
   575→            <Button
   576→              onClick={handleApplyToLive}
   577→              disabled={applying}
   578→              intent={Intent.PRIMARY}
   579→              loading={applying}
   580→            >
   581→              Confirm Apply
   582→            </Button>
   583→          </div>
   584→        </div>
   585→      </Dialog>
   586→
   587→      {/* Multi-Scenario Comparison Results */}
   588→      {comparisonResults.size >= 2 && (
   589→        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
   590→          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#ede9fe' }}>
   591→            <h3 style={{ margin: 0, fontWeight: 600, color: '#5b21b6' }}>
   592→              Scenario Comparison ({comparisonResults.size} scenarios)
   593→            </h3>
   594→            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#7c3aed' }}>
   595→              Side-by-side comparison of selected scenarios
   596→            </p>
   597→          </div>
   598→
   599→          <div style={{ overflowX: 'auto' }}>
   600→            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
   601→              <thead style={{ backgroundColor: '#f5f8fa' }}>
   602→                <tr>
   603→                  <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Metric</th>
   604→                  {Array.from(comparisonResults.keys()).map((scenarioId) => {
   605→                    const scenario = scenarios.find((s) => s.id === scenarioId);
   606→                    return (
   607→                      <th key={scenarioId} style={{ padding: 12, textAlign: 'center', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>
   608→                        {scenario?.name || 'Scenario'}
   609→                      </th>
   610→                    );
   611→                  })}
   612→                </tr>
   613→              </thead>
   614→              <tbody>
   615→                <tr style={{ borderBottom: '1px solid #e1e8ed' }}>
   616→                  <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>Projected Variance</td>
   617→                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
   618→                    const allValues = Array.from(comparisonResults.values()).map((r) => r.projectedVariance);
   619→                    const isBest = result.projectedVariance === Math.min(...allValues);
   620→                    return (
   621→                      <td key={id} style={{ padding: 12, textAlign: 'center', fontSize: 14, backgroundColor: isBest ? '#ecfdf5' : 'transparent', fontWeight: isBest ? 700 : 400, color: isBest ? '#166534' : '#5c7080' }}>
   622→                        {result.projectedVariance}%{isBest && ' ✓'}
   623→                      </td>
   624→                    );
   625→                  })}
   626→                </tr>
   627→                <tr style={{ borderBottom: '1px solid #e1e8ed' }}>
   628→                  <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>Dead Running</td>
   629→                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
   630→                    const allValues = Array.from(comparisonResults.values()).map((r) => r.projectedDeadRunning);
   631→                    const isBest = result.projectedDeadRunning === Math.min(...allValues);
   632→                    return (
   633→                      <td key={id} style={{ padding: 12, textAlign: 'center', fontSize: 14, backgroundColor: isBest ? '#ecfdf5' : 'transparent', fontWeight: isBest ? 700 : 400, color: isBest ? '#166534' : '#5c7080' }}>
   634→                        {result.projectedDeadRunning} km{isBest && ' ✓'}
   635→                      </td>
   636→                    );
   637→                  })}
   638→                </tr>
   639→              </tbody>
   640→            </table>
   641→          </div>
   642→
   643→          <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed', display: 'flex', justifyContent: 'flex-end' }}>
   644→            <Button
   645→              minimal
   646→              onClick={() => {
   647→                setComparisonResults(new Map());
   648→                setSelectedForComparison(new Set());
   649→              }}
   650→            >
   651→              Clear Comparison
   652→            </Button>
   653→          </div>
   654→        </Card>
   655→      )}
   656→
   657→      {/* Empty State */}
   658→      {scenarios.length === 0 && (
   659→        <Card elevation={Elevation.ONE} style={{ padding: 48, textAlign: 'center' }}>
   660→          <div style={{ fontSize: 48, marginBottom: 16 }}>🔬</div>
   661→          <h3 style={{ margin: '0 0 8px', fontSize: 18, fontWeight: 500, color: '#182026' }}>
   662→            No Scenarios Yet
   663→          </h3>
   664→          <p style={{ margin: 0, color: '#5c7080' }}>
   665→            Create a scenario above to start testing allocation strategies
   666→          </p>
   667→        </Card>
   668→      )}
   669→    </div>
   670→  );
   671→}
