'use client';

import React, { useState, useEffect } from 'react';
import {
  Card,
  Elevation,
  Button,
  Callout,
  Intent,
  Tag,
  InputGroup,
  Checkbox,
  HTMLSelect,
  Dialog,
  Classes,
  Spinner,
} from '@blueprintjs/core';
import { apiFetch, servicesApi, trainsApi, type Service, type Train } from '@/lib/api';

interface Scenario {
  id: string;
  name: string;
  baseDate: string;
  changeCount: number;
  createdAt: string;
}

interface ComparisonMetric {
  metric: string;
  current: number;
  projected: number;
  change: number;
  improved: boolean;
}

interface SimulationResult {
  scenarioId: string;
  projectedVariance: number;
  projectedDeadRunning: number;
  comparison: ComparisonMetric[];
}

interface AllocationChange {
  serviceId: string;
  serviceCode: string;
  origin: string;
  destination: string;
  originalTrainId: string | null;
  newTrainId: string;
}

/**
 * Simulation Panel Component
 *
 * Enables what-if scenario creation and comparison.
 */
export function SimulationPanel() {
  const [scenarios, setScenarios] = useState<Scenario[]>([]);
  const [selectedScenario, setSelectedScenario] = useState<Scenario | null>(null);
  const [simulationResult, setSimulationResult] = useState<SimulationResult | null>(null);
  const [creating, setCreating] = useState(false);
  const [running, setRunning] = useState(false);
  const [newScenarioName, setNewScenarioName] = useState('');
  const [error, setError] = useState<string | null>(null);

  // Allocation Editor state
  const [pendingServices, setPendingServices] = useState<Service[]>([]);
  const [availableTrains, setAvailableTrains] = useState<Train[]>([]);
  const [allocationChanges, setAllocationChanges] = useState<AllocationChange[]>([]);
  const [loadingServices, setLoadingServices] = useState(false);

  // Multi-scenario comparison state
  const [selectedForComparison, setSelectedForComparison] = useState<Set<string>>(new Set());
  const [comparisonResults, setComparisonResults] = useState<Map<string, SimulationResult>>(new Map());
  const [comparing, setComparing] = useState(false);

  // Apply to Live state
  const [showApplyConfirm, setShowApplyConfirm] = useState(false);
  const [applying, setApplying] = useState(false);

  // Fetch services and trains when a scenario is selected
  useEffect(() => {
    if (selectedScenario) {
      loadServicesAndTrains();
    }
  }, [selectedScenario]);

  const loadServicesAndTrains = async () => {
    setLoadingServices(true);
    setError(null);

    const [servicesResult, trainsResult] = await Promise.all([
      servicesApi.getPending(),
      trainsApi.getAll({ status: 'fit' }),
    ]);

    if (servicesResult.error) {
      setError(servicesResult.error);
    } else if (servicesResult.data) {
      setPendingServices(servicesResult.data.services);
    }

    if (trainsResult.error) {
      setError(trainsResult.error);
    } else if (trainsResult.data) {
      setAvailableTrains(trainsResult.data.trains);
    }

    setLoadingServices(false);
  };

  const handleTrainChange = (service: Service, newTrainId: string) => {
    setAllocationChanges((prev) => {
      const filtered = prev.filter((c) => c.serviceId !== service.id);

      if (!newTrainId) {
        return filtered;
      }

      return [
        ...filtered,
        {
          serviceId: service.id,
          serviceCode: service.serviceCode,
          origin: service.origin,
          destination: service.destination,
          originalTrainId: null,
          newTrainId,
        },
      ];
    });

    if (selectedScenario) {
      setScenarios((prev) =>
        prev.map((s) =>
          s.id === selectedScenario.id
            ? { ...s, changeCount: allocationChanges.length + 1 }
            : s
        )
      );
    }
  };

  const getSelectedTrainForService = (serviceId: string): string => {
    const change = allocationChanges.find((c) => c.serviceId === serviceId);
    return change?.newTrainId || '';
  };

  const removeAllocationChange = (serviceId: string) => {
    setAllocationChanges((prev) => prev.filter((c) => c.serviceId !== serviceId));
  };

  const toggleComparisonSelection = (scenarioId: string) => {
    setSelectedForComparison((prev) => {
      const next = new Set(prev);
      if (next.has(scenarioId)) {
        next.delete(scenarioId);
      } else if (next.size < 3) {
        next.add(scenarioId);
      }
      return next;
    });
  };

  const handleCompareScenarios = async () => {
    if (selectedForComparison.size < 2) {
      setError('Select at least 2 scenarios to compare');
      return;
    }

    setComparing(true);
    setError(null);
    const results = new Map<string, SimulationResult>();

    for (const scenarioId of Array.from(selectedForComparison)) {
      const scenario = scenarios.find((s) => s.id === scenarioId);
      if (!scenario || scenario.changeCount === 0) continue;

      const { data } = await apiFetch<SimulationResult>(
        `/api/simulation/${scenarioId}/run`,
        {
          method: 'POST',
          body: JSON.stringify({ changes: [] }),
        }
      );

      if (data) {
        results.set(scenarioId, data);
      }
    }

    setComparisonResults(results);
    setComparing(false);
  };

  const handleApplyToLive = async () => {
    if (!selectedScenario || allocationChanges.length === 0) return;

    setApplying(true);
    setError(null);

    const { data, error: applyError } = await apiFetch<{ applied: number }>(
      `/api/simulation/${selectedScenario.id}/apply`,
      {
        method: 'POST',
        body: JSON.stringify({
          changes: allocationChanges.map((change) => ({
            serviceId: change.serviceId,
            trainId: change.newTrainId,
          })),
        }),
      }
    );

    if (applyError) {
      setError(applyError);
    } else if (data) {
      setAllocationChanges([]);
      setSimulationResult(null);
      setShowApplyConfirm(false);
      setScenarios((prev) => prev.filter((s) => s.id !== selectedScenario.id));
      setSelectedScenario(null);
    }

    setApplying(false);
  };

  const handleCreateScenario = async () => {
    if (!newScenarioName.trim()) return;

    setCreating(true);
    setError(null);

    const { data, error } = await apiFetch<{ scenarioId: string } & Scenario>(
      '/api/simulation/create',
      {
        method: 'POST',
        body: JSON.stringify({
          name: newScenarioName,
          baseDate: new Date().toISOString().split('T')[0],
        }),
      }
    );

    if (error) {
      setError(error);
    } else if (data) {
      const newScenario: Scenario = {
        id: data.scenarioId,
        name: newScenarioName,
        baseDate: new Date().toISOString().split('T')[0],
        changeCount: 0,
        createdAt: new Date().toISOString(),
      };
      setScenarios((prev) => [...prev, newScenario]);
      setSelectedScenario(newScenario);
      setNewScenarioName('');
    }

    setCreating(false);
  };

  const handleRunSimulation = async () => {
    if (!selectedScenario) return;

    if (allocationChanges.length === 0) {
      setError('Please assign at least one train to a service before running simulation');
      return;
    }

    setRunning(true);
    setError(null);

    const { data, error: simError } = await apiFetch<SimulationResult>(
      `/api/simulation/${selectedScenario.id}/run`,
      {
        method: 'POST',
        body: JSON.stringify({
          changes: allocationChanges.map((change) => ({
            serviceId: change.serviceId,
            originalTrainId: change.originalTrainId,
            newTrainId: change.newTrainId,
          })),
        }),
      }
    );

    if (simError) {
      setError(simError);
    } else if (data) {
      setSimulationResult(data);
    }

    setRunning(false);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
      {/* Create New Scenario */}
      <Card elevation={Elevation.ONE} style={{ padding: 24 }}>
        <h2 style={{ margin: '0 0 8px', fontSize: 18, fontWeight: 600, color: '#182026' }}>
          What-If Simulation
        </h2>
        <p style={{ margin: '0 0 16px', fontSize: 14, color: '#5c7080' }}>
          Create scenarios to test different allocation strategies and see projected impact on km variance.
        </p>

        <div style={{ display: 'flex', gap: 16 }}>
          <InputGroup
            value={newScenarioName}
            onChange={(e) => setNewScenarioName(e.target.value)}
            placeholder="Scenario name (e.g., Q1 Rebalancing)"
            style={{ flex: 1 }}
          />
          <Button
            onClick={handleCreateScenario}
            disabled={creating || !newScenarioName.trim()}
            intent={Intent.PRIMARY}
            loading={creating}
          >
            Create Scenario
          </Button>
        </div>

        {error && (
          <Callout intent={Intent.DANGER} style={{ marginTop: 16 }}>
            {error}
          </Callout>
        )}
      </Card>

      {/* Scenarios List */}
      {scenarios.length > 0 && (
        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#f5f8fa', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <div>
              <h3 style={{ margin: 0, fontWeight: 600, color: '#182026' }}>Your Scenarios</h3>
              <p style={{ margin: '4px 0 0', fontSize: 12, color: '#5c7080' }}>Select up to 3 scenarios to compare</p>
            </div>
            {selectedForComparison.size >= 2 && (
              <Button
                onClick={handleCompareScenarios}
                disabled={comparing}
                intent={Intent.NONE}
                loading={comparing}
                style={{ backgroundColor: '#7c3aed', color: 'white' }}
              >
                Compare {selectedForComparison.size} Scenarios
              </Button>
            )}
          </div>
          <div>
            {scenarios.map((scenario) => (
              <div
                key={scenario.id}
                style={{
                  padding: 16,
                  borderBottom: '1px solid #e1e8ed',
                  backgroundColor: selectedScenario?.id === scenario.id ? '#e1e8ed' : selectedForComparison.has(scenario.id) ? '#ede9fe' : 'transparent',
                  borderLeft: selectedScenario?.id === scenario.id ? '4px solid #2563eb' : '4px solid transparent',
                }}
              >
                <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
                  <Checkbox
                    checked={selectedForComparison.has(scenario.id)}
                    onChange={() => toggleComparisonSelection(scenario.id)}
                  />
                  <div
                    style={{ flex: 1, cursor: 'pointer' }}
                    onClick={() => setSelectedScenario(scenario)}
                  >
                    <div style={{ fontWeight: 500, color: '#182026' }}>{scenario.name}</div>
                    <div style={{ fontSize: 14, color: '#5c7080' }}>
                      Base: {scenario.baseDate} • Changes: {scenario.changeCount}
                    </div>
                  </div>
                  {selectedScenario?.id === scenario.id && (
                    <Button
                      onClick={(e: React.MouseEvent) => {
                        e.stopPropagation();
                        handleRunSimulation();
                      }}
                      disabled={running}
                      intent={Intent.SUCCESS}
                      loading={running}
                      small
                    >
                      Run Simulation
                    </Button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </Card>
      )}

      {/* Allocation Editor */}
      {selectedScenario && (
        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#eff6ff' }}>
            <h3 style={{ margin: 0, fontWeight: 600, color: '#1e40af' }}>
              Allocation Editor: {selectedScenario.name}
            </h3>
            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#3b82f6' }}>
              Assign trains to pending services. Changes: {allocationChanges.length}
            </p>
          </div>

          {loadingServices ? (
            <div style={{ padding: 32, textAlign: 'center' }}>
              <Spinner size={24} />
              <p style={{ marginTop: 8, color: '#5c7080' }}>Loading services and trains...</p>
            </div>
          ) : pendingServices.length === 0 ? (
            <div style={{ padding: 32, textAlign: 'center', color: '#5c7080' }}>
              No pending services found for today.
            </div>
          ) : (
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead style={{ backgroundColor: '#f5f8fa' }}>
                  <tr>
                    <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Service</th>
                    <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Route</th>
                    <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Distance</th>
                    <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Assign Train</th>
                  </tr>
                </thead>
                <tbody>
                  {pendingServices.slice(0, 10).map((service) => (
                    <tr
                      key={service.id}
                      style={{
                        borderBottom: '1px solid #e1e8ed',
                        backgroundColor: getSelectedTrainForService(service.id) ? '#ecfdf5' : 'transparent',
                      }}
                    >
                      <td style={{ padding: 12 }}>
                        <div style={{ fontWeight: 500, color: '#182026' }}>{service.serviceCode}</div>
                        <div style={{ fontSize: 12, color: '#5c7080' }}>{service.departureTime?.slice(0, 5) || '--:--'}</div>
                      </td>
                      <td style={{ padding: 12, fontSize: 14, color: '#5c7080' }}>
                        {service.origin} → {service.destination}
                      </td>
                      <td style={{ padding: 12, fontSize: 14, color: '#5c7080' }}>
                        {service.distanceKm} km
                      </td>
                      <td style={{ padding: 12 }}>
                        <HTMLSelect
                          value={getSelectedTrainForService(service.id)}
                          onChange={(e) => handleTrainChange(service, e.target.value)}
                          fill
                        >
                          <option value="">-- Select Train --</option>
                          {availableTrains.map((train) => (
                            <option key={train.id} value={train.id}>
                              {train.trainId} ({train.currentKm.toLocaleString()} km, {train.deltaPercent > 0 ? '+' : ''}{train.deltaPercent.toFixed(1)}%)
                            </option>
                          ))}
                        </HTMLSelect>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Summary of Changes */}
          {allocationChanges.length > 0 && (
            <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed' }}>
              <h4 style={{ margin: '0 0 8px', fontWeight: 500, color: '#182026' }}>
                Pending Changes ({allocationChanges.length})
              </h4>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                {allocationChanges.map((change) => {
                  const train = availableTrains.find((t) => t.id === change.newTrainId);
                  return (
                    <Tag key={change.serviceId} intent={Intent.PRIMARY} minimal interactive onRemove={() => removeAllocationChange(change.serviceId)}>
                      {change.serviceCode} → {train?.trainId || change.newTrainId}
                    </Tag>
                  );
                })}
              </div>
            </div>
          )}
        </Card>
      )}

      {/* Simulation Results */}
      {simulationResult && (
        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#ecfdf5' }}>
            <h3 style={{ margin: 0, fontWeight: 600, color: '#166534' }}>Simulation Results</h3>
            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#22c55e' }}>
              Projected impact of {selectedScenario?.name}
            </p>
          </div>

          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead style={{ backgroundColor: '#f5f8fa' }}>
                <tr>
                  <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Metric</th>
                  <th style={{ padding: 12, textAlign: 'right', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Current</th>
                  <th style={{ padding: 12, textAlign: 'right', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Projected</th>
                  <th style={{ padding: 12, textAlign: 'right', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Change</th>
                </tr>
              </thead>
              <tbody>
                {simulationResult.comparison.map((metric) => (
                  <tr key={metric.metric} style={{ borderBottom: '1px solid #e1e8ed' }}>
                    <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>{metric.metric}</td>
                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', color: '#5c7080' }}>{metric.current}</td>
                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', fontWeight: 500, color: '#182026' }}>{metric.projected}</td>
                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', fontWeight: 500, color: metric.improved ? '#22c55e' : '#dc2626' }}>
                      {metric.change > 0 ? '+' : ''}{metric.change}
                      {metric.improved && ' ✓'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <div>
              <span style={{ fontSize: 14, color: '#5c7080', marginRight: 16 }}>
                Projected Variance: <strong>{simulationResult.projectedVariance}%</strong>
              </span>
              <span style={{ fontSize: 14, color: '#5c7080' }}>
                Dead Running: <strong>{simulationResult.projectedDeadRunning} km</strong>
              </span>
            </div>
            <Button
              onClick={() => setShowApplyConfirm(true)}
              disabled={allocationChanges.length === 0}
              intent={Intent.PRIMARY}
            >
              Apply to Live
            </Button>
          </div>
        </Card>
      )}

      {/* Apply to Live Confirmation Dialog */}
      <Dialog
        isOpen={showApplyConfirm}
        onClose={() => setShowApplyConfirm(false)}
        title="Confirm Apply to Live"
      >
        <div className={Classes.DIALOG_BODY}>
          <p>
            This will create {allocationChanges.length} new allocation(s) in the live system.
            This action cannot be undone.
          </p>
          <Callout intent={Intent.WARNING} style={{ marginTop: 16 }}>
            <strong>Changes to apply:</strong>
            <ul style={{ marginTop: 8, paddingLeft: 20 }}>
              {allocationChanges.slice(0, 5).map((change) => (
                <li key={change.serviceId}>
                  {change.serviceCode}: Assign train {change.newTrainId.slice(0, 8)}...
                </li>
              ))}
              {allocationChanges.length > 5 && (
                <li>... and {allocationChanges.length - 5} more</li>
              )}
            </ul>
          </Callout>
        </div>
        <div className={Classes.DIALOG_FOOTER}>
          <div className={Classes.DIALOG_FOOTER_ACTIONS}>
            <Button onClick={() => setShowApplyConfirm(false)}>Cancel</Button>
            <Button
              onClick={handleApplyToLive}
              disabled={applying}
              intent={Intent.PRIMARY}
              loading={applying}
            >
              Confirm Apply
            </Button>
          </div>
        </div>
      </Dialog>

      {/* Multi-Scenario Comparison Results */}
      {comparisonResults.size >= 2 && (
        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#ede9fe' }}>
            <h3 style={{ margin: 0, fontWeight: 600, color: '#5b21b6' }}>
              Scenario Comparison ({comparisonResults.size} scenarios)
            </h3>
            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#7c3aed' }}>
              Side-by-side comparison of selected scenarios
            </p>
          </div>

          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead style={{ backgroundColor: '#f5f8fa' }}>
                <tr>
                  <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Metric</th>
                  {Array.from(comparisonResults.keys()).map((scenarioId) => {
                    const scenario = scenarios.find((s) => s.id === scenarioId);
                    return (
                      <th key={scenarioId} style={{ padding: 12, textAlign: 'center', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>
                        {scenario?.name || 'Scenario'}
                      </th>
                    );
                  })}
                </tr>
              </thead>
              <tbody>
                <tr style={{ borderBottom: '1px solid #e1e8ed' }}>
                  <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>Projected Variance</td>
                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
                    const allValues = Array.from(comparisonResults.values()).map((r) => r.projectedVariance);
                    const isBest = result.projectedVariance === Math.min(...allValues);
                    return (
                      <td key={id} style={{ padding: 12, textAlign: 'center', fontSize: 14, backgroundColor: isBest ? '#ecfdf5' : 'transparent', fontWeight: isBest ? 700 : 400, color: isBest ? '#166534' : '#5c7080' }}>
                        {result.projectedVariance}%{isBest && ' ✓'}
                      </td>
                    );
                  })}
                </tr>
                <tr style={{ borderBottom: '1px solid #e1e8ed' }}>
                  <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>Dead Running</td>
                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
                    const allValues = Array.from(comparisonResults.values()).map((r) => r.projectedDeadRunning);
                    const isBest = result.projectedDeadRunning === Math.min(...allValues);
                    return (
                      <td key={id} style={{ padding: 12, textAlign: 'center', fontSize: 14, backgroundColor: isBest ? '#ecfdf5' : 'transparent', fontWeight: isBest ? 700 : 400, color: isBest ? '#166534' : '#5c7080' }}>
                        {result.projectedDeadRunning} km{isBest && ' ✓'}
                      </td>
                    );
                  })}
                </tr>
              </tbody>
            </table>
          </div>

          <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed', display: 'flex', justifyContent: 'flex-end' }}>
            <Button
              minimal
              onClick={() => {
                setComparisonResults(new Map());
                setSelectedForComparison(new Set());
              }}
            >
              Clear Comparison
            </Button>
          </div>
        </Card>
      )}

      {/* Empty State */}
      {scenarios.length === 0 && (
        <Card elevation={Elevation.ONE} style={{ padding: 48, textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🔬</div>
          <h3 style={{ margin: '0 0 8px', fontSize: 18, fontWeight: 500, color: '#182026' }}>
            No Scenarios Yet
          </h3>
          <p style={{ margin: 0, color: '#5c7080' }}>
            Create a scenario above to start testing allocation strategies
          </p>
        </Card>
      )}
    </div>
  );
}

/**
 * Km Balancing Page
 *
 * Displays mileage distribution, variance analysis, and simulation tools.
 * Shows histogram, train ranking by delta, and what-if scenarios.
 */

import { Card, Elevation, H1, Classes } from '@blueprintjs/core';
import { BalancingDashboard, SimulationPanel } from '@/components/balancing';

export default function BalancingPage() {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
      <Card elevation={Elevation.ONE}>
        <H1>Km Balancing</H1>
        <p className={Classes.TEXT_MUTED}>
          Analyze mileage distribution, identify balancing opportunities, and run what-if simulations
        </p>
      </Card>

      {/* Distribution and Ranking Dashboard */}
      <BalancingDashboard />

      {/* What-If Simulation Panel */}
      <SimulationPanel />
    </div>
  );
}

