/**
 * MMS - API Client Utilities
 *
 * Centralized API client for backend communication
 */

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000';

interface ApiResponse<T> {
  data: T | null;
  error: string | null;
}

/**
 * Generic fetch wrapper with error handling
 */
export async function apiFetch<T>(endpoint: string, options?: RequestInit): Promise<ApiResponse<T>> {
  try {
    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options?.headers,
      },
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      return {
        data: null,
        error: errorData.error || `API Error: ${response.status}`,
      };
    }

    const data = await response.json();
    return { data, error: null };
  } catch (err) {
    return {
      data: null,
      error: err instanceof Error ? err.message : 'Network error',
    };
  }
}

/**
 * Dashboard API
 */
export interface DashboardSummary {
  totalTrains: number;
  availableTrains: number;
  inMaintenanceCount: number;
  kmVariance: number;
  varianceStatus: 'green' | 'yellow' | 'red';
}

export interface DepotCapacity {
  id: string;
  name: string;
  code: string;
  currentOccupancy: number;
  maxCapacity: number;
  percentUsed: number;
}

export interface DepotCapacityResponse {
  depots: DepotCapacity[];
}

export interface MaintenanceAlert {
  id: string;
  trainId: string;
  type: 'PM1' | 'PM2' | 'HM' | 'OVH';
  date: string;
  depot: string;
  depotCode: string;
  durationDays: number;
}

export interface MaintenanceAlertsResponse {
  totalUpcoming: number;
  countByType: {
    PM1: number;
    PM2: number;
    HM: number;
    OVH: number;
  };
  alerts: MaintenanceAlert[];
}

export const dashboardApi = {
  getSummary: () => apiFetch<DashboardSummary>('/api/dashboard/summary'),
  getDepotCapacity: () => apiFetch<DepotCapacityResponse>('/api/dashboard/depot-capacity'),
  getMaintenanceAlerts: () => apiFetch<MaintenanceAlertsResponse>('/api/dashboard/maintenance-alerts'),
};

/**
 * Trains API
 */
export interface Train {
  id: string;
  trainId: string;
  fleetId: string;
  baseDepotId: string;
  currentKm: number;
  targetKm: number;
  fitnessStatus: 'fit' | 'unfit';
  lastMaintenanceDate: string | null;
  nextMaintenanceKm: number | null;
  latitude: string | null;
  longitude: string | null;
  fleet: {
    id: string;
    name: string;
    manufacturer: string | null;
  } | null;
  baseDepot: {
    id: string;
    name: string;
    code: string;
    latitude: string | null;
    longitude: string | null;
  } | null;
  deltaFromAverage: number;
  deltaPercent: number;
}

export interface TrainsResponse {
  trains: Train[];
}

export interface Depot {
  id: string;
  name: string;
  code: string;
  latitude: string | null;
  longitude: string | null;
  capacityTracks: number;
  capacityManhours: number;
}

export interface DepotsResponse {
  depots: Depot[];
}

export const trainsApi = {
  getAll: (params?: { status?: string; depot?: string }) => {
    const query = new URLSearchParams();
    if (params?.status) query.set('status', params.status);
    if (params?.depot) query.set('depot', params.depot);
    const queryStr = query.toString();
    return apiFetch<TrainsResponse>(`/api/trains${queryStr ? `?${queryStr}` : ''}`);
  },
  getById: (id: string) => apiFetch<Train>(`/api/trains/${id}`),
};

export const depotsApi = {
  getAll: () => apiFetch<DepotsResponse>('/api/depots'),
};

/**
 * Services API
 */
export interface Service {
  id: string;
  serviceCode: string;
  origin: string;
  destination: string;
  distanceKm: number;
  departureTime: string;
  arrivalTime: string;
  serviceType: string;
}

export interface PendingServicesResponse {
  date: string;
  services: Service[];
}

export const servicesApi = {
  getPending: (date?: string) => {
    const query = date ? `?date=${date}` : '';
    return apiFetch<PendingServicesResponse>(`/api/services/pending${query}`);
  },
};

/**
 * Allocations API
 */
export interface Recommendation {
  trainId: string;
  train_id: string;
  score: number;
  justifications: string[];
  deadRunningKm: number;
}

export interface RecommendationsResponse {
  recommendations: Recommendation[];
  solverTimeMs: number;
  fallback?: boolean;
}

export interface Allocation {
  id: string;
  serviceId: string;
  trainId: string;
  allocationDate: string;
  status: string;
  score: number | null;
  justifications: string[] | null;
}

export interface AllocationResponse {
  allocation: Allocation;
}

export const allocationsApi = {
  recommend: (serviceId: string, date: string) =>
    apiFetch<RecommendationsResponse>('/api/allocations/recommend', {
      method: 'POST',
      body: JSON.stringify({ serviceId, date }),
    }),
  create: (serviceId: string, trainId: string, date: string, score?: number, justifications?: string[]) =>
    apiFetch<AllocationResponse>('/api/allocations', {
      method: 'POST',
      body: JSON.stringify({ serviceId, trainId, date, score, justifications }),
    }),
};

// Helper function for POST requests
async function apiFetchWithBody<T>(endpoint: string, options: RequestInit): Promise<ApiResponse<T>> {
  try {
    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      return {
        data: null,
        error: errorData.error || `API Error: ${response.status}`,
      };
    }

    const data = await response.json();
    return { data, error: null };
  } catch (err) {
    return {
      data: null,
      error: err instanceof Error ? err.message : 'Network error',
    };
  }
}

